VALUES ('81c2999e-754a-4964-9b25-85541ce57458', 'What is the slope of the line?', 'A line passes through points $(5, 11)$ and $(9, 19)$ in the $xy$-plane.', NULL, '[{"id":"A","text":"$1$","is_correct":false,"explanation":"Incorrect rise over run."},{"id":"B","text":"$2$","is_correct":true,"explanation":"Slope = $\\frac{19-11}{9-5} = 2$."},{"id":"C","text":"$3$","is_correct":false,"explanation":"Adds 1 to the slope."},{"id":"D","text":"$19$","is_correct":false,"explanation":"That is a $y$-coordinate, not slope."}]'::jsonb, 'B', 'Slope = $\frac{8}{4} = 2$.', NULL, 'Problem-Solving and Data Analysis', 'Two-variable data', 'math', 'psda', 'TVA', 'TVA', 'hard', true, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_bulk_v1","original":true,"explanation_v2":true}'::jsonb, now(), now())
